INSERT INTO `ArtikelKesehatan` (`id`, `perawatId`, `judul`, `konten`, `kategori`, `gambar`, `tags`, `status`, `viewCount`, `createdAt`, `updatedAt`) VALUES
('nutri-001', 'cmf40bfoh0002f5rw6xctx5y7', 'Panduan Lengkap Pola Makan Sehat untuk Penderita Hipertensi', 
'Hipertensi atau tekanan darah tinggi merupakan kondisi yang memerlukan perhatian khusus dalam hal pola makan. Artikel ini akan membahas secara mendalam tentang diet DASH (Dietary Approaches to Stop Hypertension) yang terbukti efektif menurunkan tekanan darah.\n\n## Prinsip Dasar Diet DASH\n\nDiet DASH menekankan pada:\n- Konsumsi buah dan sayuran segar (8-10 porsi per hari)\n- Produk susu rendah lemak (2-3 porsi per hari)\n- Biji-bijian utuh\n- Kacang-kacangan dan polong-polongan\n- Ikan, unggas tanpa kulit\n- Minyak nabati sehat\n\n## Makanan yang Harus Dihindari\n\n1. **Garam berlebih**: Batasi konsumsi natrium maksimal 1500-2300 mg per hari\n2. **Makanan olahan**: Sosis, nugget, makanan kaleng\n3. **Lemak jenuh**: Daging berlemak, mentega, keju penuh lemak\n4. **Gula tambahan**: Minuman manis, permen, kue\n\n## Menu Harian Contoh\n\n**Sarapan:**\n- Oatmeal dengan potongan buah segar\n- Susu rendah lemak\n- Roti gandum dengan selai kacang\n\n**Makan Siang:**\n- Nasi merah\n- Ikan panggang dengan bumbu rempah\n- Sayur bayam tumis\n- Buah jeruk\n\n**Makan Malam:**\n- Sup ayam dengan sayuran\n- Kentang rebus\n- Salad hijau dengan minyak zaitun\n\n## Tips Praktis\n\n- Gunakan rempah-rempah sebagai pengganti garam\n- Baca label nutrisi pada kemasan makanan\n- Masak sendiri makanan untuk mengontrol bahan\n- Perbanyak konsumsi kalium dari pisang, alpukat, tomat\n- Minum air putih minimal 8 gelas per hari\n\n## Manfaat Diet DASH\n\nPenelitian menunjukkan diet DASH dapat:\n- Menurunkan tekanan darah sistolik 8-14 mmHg\n- Mengurangi risiko penyakit jantung\n- Membantu menurunkan berat badan\n- Meningkatkan kesehatan secara keseluruhan\n\nKonsultasikan dengan dokter atau ahli gizi untuk penyesuaian diet sesuai kondisi kesehatan Anda.', 
'Nutrisi', 'https://images.unsplash.com/photo-1494390248081-4e521a5940db', 'hipertensi,diet,nutrisi,kesehatan', 'PUBLISHED', 156, NOW(), NOW()),

('nutri-002', 'cmf40bfoh0002f5rw6xctx5y7', 'Superfood Lokal Indonesia: Kaya Nutrisi dan Terjangkau',
'Indonesia memiliki beragam superfood lokal yang tidak kalah bergizi dengan superfood impor. Artikel ini mengulas berbagai makanan super asli Indonesia yang mudah ditemukan dan terjangkau.\n\n## Apa itu Superfood?\n\nSuperfood adalah makanan yang mengandung nutrisi sangat tinggi dan memberikan manfaat kesehatan luar biasa. Tidak perlu mahal, superfood lokal Indonesia justru lebih segar dan sesuai dengan tubuh kita.\n\n## 10 Superfood Lokal Indonesia\n\n### 1. Tempe\n- Tinggi protein nabati (20g per 100g)\n- Mengandung vitamin B12\n- Probiotik alami untuk kesehatan pencernaan\n- Isoflavon untuk kesehatan jantung\n\n### 2. Daun Kelor (Moringa)\n- 7x vitamin C dari jeruk\n- 4x kalsium dari susu\n- 4x vitamin A dari wortel\n- 3x kalium dari pisang\n\n### 3. Kunyit\n- Kurkumin sebagai anti-inflamasi\n- Meningkatkan daya tahan tubuh\n- Baik untuk kesehatan otak\n- Antioksidan tinggi\n\n### 4. Ubi Ungu\n- Antosianin untuk kesehatan mata\n- Serat tinggi untuk pencernaan\n- Indeks glikemik rendah\n- Vitamin A dan C\n\n### 5. Pare\n- Menurunkan kadar gula darah\n- Meningkatkan metabolisme\n- Vitamin C dan folat\n- Antioksidan kuat\n\n### 6. Buah Naga Merah\n- Likopen untuk kesehatan jantung\n- Serat untuk pencernaan\n- Vitamin C dan B\n- Rendah kalori\n\n### 7. Jambu Biji Merah\n- Vitamin C tertinggi (200mg/100g)\n- Likopen untuk anti kanker\n- Serat larut untuk kolesterol\n- Kalium untuk tekanan darah\n\n### 8. Bengkoang\n- Inulin untuk kesehatan usus\n- Vitamin C untuk kulit\n- Rendah kalori\n- Menyegarkan dan menghidrasi\n\n### 9. Daun Katuk\n- Meningkatkan produksi ASI\n- Protein nabati tinggi\n- Zat besi untuk anemia\n- Vitamin A, B, C\n\n### 10. Beras Merah\n- Serat tinggi\n- Vitamin B kompleks\n- Mineral lengkap\n- Indeks glikemik rendah\n\n## Cara Mengonsumsi Optimal\n\n**Tips Pengolahan:**\n- Kukus atau rebus untuk mempertahankan nutrisi\n- Konsumsi beragam warna untuk nutrisi lengkap\n- Kombinasikan beberapa superfood dalam satu menu\n- Konsumsi rutin dalam porsi seimbang\n\n## Resep Smoothie Superfood Lokal\n\n**Bahan:**\n- 1 buah naga merah\n- 1 buah jambu biji merah\n- 1 ruas kunyit segar\n- 1 sdm madu lokal\n- 200ml air kelapa\n\n**Cara membuat:**\n1. Blender semua bahan hingga halus\n2. Saring jika perlu\n3. Sajikan dingin\n\n## Kesimpulan\n\nSuperfood lokal Indonesia tidak hanya bergizi tinggi tetapi juga mendukung petani lokal dan ramah lingkungan. Mulailah memasukkan superfood lokal dalam menu harian Anda untuk kesehatan optimal.',
'Nutrisi', 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd', 'superfood,nutrisi,makanan lokal,kesehatan', 'PUBLISHED', 234, NOW(), NOW());

