INSERT INTO `ArtikelKesehatan` (`id`, `perawatId`, `judul`, `konten`, `kategori`, `gambar`, `tags`, `status`, `viewCount`, `createdAt`, `updatedAt`) VALUES
('olahraga-001', 'cmf40bfoh0002f5rw6xctx5y7', 'Program Latihan 30 Hari untuk Pemula: Mulai Hidup Sehat dari Rumah',
'Memulai rutinitas olahraga bisa terasa menantang, terutama bagi pemula. Program 30 hari ini dirancang khusus untuk membantu Anda membangun kebiasaan berolahraga secara bertahap dan aman.\n\n## Mengapa 30 Hari?\n\nPenelitian menunjukkan bahwa dibutuhkan rata-rata 21-30 hari untuk membentuk kebiasaan baru. Program ini dirancang untuk:\n- Membangun kekuatan dasar\n- Meningkatkan stamina\n- Membentuk kebiasaan sehat\n- Mencegah cedera\n\n## Persiapan Sebelum Memulai\n\n**Peralatan yang dibutuhkan:**\n- Matras yoga\n- Botol air minum\n- Handuk kecil\n- Sepatu olahraga yang nyaman\n- Timer atau aplikasi stopwatch\n\n**Pemeriksaan kesehatan:**\nKonsultasikan dengan dokter jika Anda memiliki:\n- Penyakit jantung\n- Diabetes\n- Masalah persendian\n- Kondisi kesehatan kronis lainnya\n\n## Program 30 Hari\n\n### Minggu 1: Fondasi (Hari 1-7)\n**Senin, Rabu, Jumat:**\n- Pemanasan: Jalan di tempat (5 menit)\n- Push-up dinding: 10 repetisi x 2 set\n- Squat kursi: 10 repetisi x 2 set\n- Marching: 1 menit x 2 set\n- Pendinginan: Stretching (5 menit)\n\n**Selasa, Kamis, Sabtu:**\n- Jalan santai 15-20 menit\n- Stretching ringan\n\n**Minggu:** Istirahat aktif (jalan santai atau yoga ringan)\n\n### Minggu 2: Peningkatan (Hari 8-14)\n**Senin, Rabu, Jumat:**\n- Pemanasan: Jumping jack ringan (5 menit)\n- Push-up lutut: 12 repetisi x 2 set\n- Squat biasa: 12 repetisi x 2 set\n- Plank: 20 detik x 2 set\n- Mountain climbers: 10 repetisi x 2 set\n- Pendinginan: Stretching (7 menit)\n\n**Selasa, Kamis, Sabtu:**\n- Jalan cepat 20-25 menit\n- Core exercise ringan\n\n### Minggu 3: Tantangan (Hari 15-21)\n**Senin, Rabu, Jumat:**\n- Pemanasan: Dynamic stretching (5 menit)\n- Push-up standar: 15 repetisi x 3 set\n- Squat jump: 10 repetisi x 3 set\n- Plank: 30 detik x 3 set\n- Burpees modifikasi: 8 repetisi x 2 set\n- Lunges: 10 repetisi per kaki x 2 set\n- Pendinginan: Stretching (10 menit)\n\n**Selasa, Kamis:**\n- Jogging ringan 15 menit\n- Yoga 15 menit\n\n**Sabtu:** Aktivitas fun (berenang, bersepeda, atau dancing)\n\n### Minggu 4: Konsolidasi (Hari 22-30)\n**Senin, Rabu, Jumat:**\n- Circuit training 30 menit:\n  - Push-up: 1 menit\n  - Squat: 1 menit\n  - Plank: 1 menit\n  - Jumping jack: 1 menit\n  - Rest: 1 menit\n  - Ulangi 4-5 kali\n\n**Selasa, Kamis:**\n- Kombinasi cardio dan strength training\n- Total 30-40 menit\n\n## Tips Sukses\n\n1. **Konsistensi > Intensitas**: Lebih baik olahraga ringan setiap hari daripada keras sekali seminggu\n2. **Dengarkan tubuh**: Istirahat jika merasa sakit atau terlalu lelah\n3. **Hidrasi**: Minum air sebelum, selama, dan setelah olahraga\n4. **Nutrisi**: Makan makanan seimbang untuk mendukung pemulihan\n5. **Tidur cukup**: 7-8 jam untuk pemulihan optimal\n6. **Track progress**: Catat perkembangan Anda\n\n## Setelah 30 Hari\n\nSelamat! Anda telah membangun fondasi kebugaran. Langkah selanjutnya:\n- Tingkatkan intensitas secara bertahap\n- Coba variasi olahraga baru\n- Tetapkan goal jangka panjang\n- Bergabung dengan komunitas fitness\n\nIngat, perjalanan kesehatan adalah marathon, bukan sprint!',
'Olahraga', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b', 'olahraga,fitness,pemula,home workout', 'PUBLISHED', 342, NOW(), NOW()),

('olahraga-002', 'cmf40bfoh0002f5rw6xctx5y7', 'Yoga untuk Kesehatan Mental: 8 Pose Efektif Redakan Stres dan Kecemasan',
'Yoga bukan hanya tentang fleksibilitas fisik, tetapi juga kesehatan mental. Penelitian menunjukkan yoga dapat mengurangi kortisol (hormon stres) hingga 23%. Berikut panduan lengkap yoga untuk kesehatan mental.\n\n## Manfaat Yoga untuk Mental\n\n- Mengurangi anxiety dan depresi\n- Meningkatkan kualitas tidur\n- Memperbaiki fokus dan konsentrasi\n- Meningkatkan self-awareness\n- Menstabilkan mood\n- Mengurangi gejala PTSD\n\n## Persiapan Praktik Yoga\n\n**Yang dibutuhkan:**\n- Matras yoga anti-slip\n- Pakaian nyaman dan elastis\n- Ruangan tenang\n- Musik meditasi (opsional)\n- Essential oil lavender (opsional)\n\n**Waktu terbaik:**\n- Pagi hari untuk energi positif\n- Sore hari untuk melepas stres\n- Malam hari untuk tidur lebih nyenyak\n\n## 8 Pose Yoga untuk Kesehatan Mental\n\n### 1. Child\'s Pose (Balasana)\n**Manfaat:** Menenangkan sistem saraf, mengurangi anxiety\n**Cara:**\n- Berlutut di matras\n- Duduk di tumit, rentangkan lutut selebar pinggul\n- Bungkukkan badan ke depan, dahi menyentuh matras\n- Rentangkan tangan ke depan atau di samping tubuh\n- Tahan 1-3 menit dengan napas dalam\n\n### 2. Cat-Cow Pose (Marjaryasana-Bitilasana)\n**Manfaat:** Melepaskan ketegangan punggung dan leher\n**Cara:**\n- Posisi merangkak, tangan di bawah bahu\n- Tarik napas, lengkungkan punggung ke bawah (Cow)\n- Buang napas, lengkungkan punggung ke atas (Cat)\n- Ulangi 10-15 kali dengan ritme napas\n\n### 3. Standing Forward Bend (Uttanasana)\n**Manfaat:** Menenangkan pikiran, mengurangi fatigue\n**Cara:**\n- Berdiri tegak, kaki selebar pinggul\n- Bungkukkan badan dari pinggul\n- Biarkan tangan menggantung atau pegang siku\n- Tahan 30-60 detik\n\n### 4. Legs-Up-The-Wall (Viparita Karani)\n**Manfaat:** Mengurangi anxiety, meningkatkan sirkulasi\n**Cara:**\n- Berbaring dekat dinding\n- Angkat kaki lurus ke dinding\n- Rentangkan tangan di samping\n- Tahan 5-15 menit\n\n### 5. Bridge Pose (Setu Bandhasana)\n**Manfaat:** Membuka dada, mengurangi depresi ringan\n**Cara:**\n- Berbaring telentang, tekuk lutut\n- Angkat pinggul ke atas\n- Kaitkan tangan di bawah punggung\n- Tahan 30-60 detik\n\n### 6. Corpse Pose (Savasana)\n**Manfaat:** Relaksasi total, mengurangi insomnia\n**Cara:**\n- Berbaring telentang\n- Rentangkan kaki dan tangan\n- Tutup mata, fokus pada napas\n- Tahan 5-10 menit\n\n### 7. Easy Pose dengan Pranayama (Sukhasana)\n**Manfaat:** Meditasi, menenangkan pikiran\n**Cara:**\n- Duduk bersila nyaman\n- Punggung lurus, tangan di lutut\n- Praktikkan pernapasan 4-7-8\n- Lakukan 5-10 menit\n\n### 8. Warrior II (Virabhadrasana II)\n**Manfaat:** Membangun kepercayaan diri, grounding\n**Cara:**\n- Berdiri dengan kaki terbuka lebar\n- Putar kaki kanan 90 derajat\n- Tekuk lutut kanan, rentangkan tangan\n- Tahan 30 detik per sisi\n\n## Teknik Pernapasan (Pranayama)\n\n### Box Breathing\n- Tarik napas 4 hitungan\n- Tahan 4 hitungan\n- Buang napas 4 hitungan\n- Tahan 4 hitungan\n- Ulangi 4-8 kali\n\n### 4-7-8 Breathing\n- Tarik napas 4 hitungan\n- Tahan 7 hitungan\n- Buang napas 8 hitungan\n- Sangat efektif untuk anxiety attack\n\n## Membuat Rutinitas Yoga\n\n**Pemula (15 menit):**\n- Child\'s Pose (3 menit)\n- Cat-Cow (3 menit)\n- Easy Pose + Breathing (5 menit)\n- Savasana (4 menit)\n\n**Intermediate (30 menit):**\n- Semua pose di atas\n- 2-3 menit per pose\n- Fokus pada transisi halus\n\n## Tips Praktik\n\n1. Mulai perlahan, jangan memaksakan\n2. Fokus pada napas, bukan kesempurnaan pose\n3. Praktik rutin lebih baik dari durasi lama\n4. Jurnal perasaan setelah yoga\n5. Kombinasikan dengan meditasi mindfulness\n\nYoga adalah journey, bukan destination. Setiap praktik membawa Anda lebih dekat pada kedamaian mental.',
'Olahraga', 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b', 'yoga,kesehatan mental,stres,meditasi', 'PUBLISHED', 289, NOW(), NOW());

